import { Routes, Route } from 'react-router-dom';
import LandingPage from './pages/LandingPage';
import SignupLogin from './pages/SignupLogin';
import Dashboard from './pages/Dashboard';
import TravelStories from './pages/TravelStories';
import VerifiedStays from './pages/VerifiedStays';
import Settings from './pages/Settings';

function AppRoutes() {
  return (
    <Routes>
      <Route path="/" element={<LandingPage />} />
      {/* Separate Sign Up and Login routes */}
      <Route path="/signup" element={<SignupLogin />} />
      <Route path="/login" element={<SignupLogin />} />

      <Route path="/dashboard" element={<Dashboard />} />
      <Route path="/travel-stories" element={<TravelStories />} />
      <Route path="/verified-stays" element={<VerifiedStays />} />
      <Route path="/settings" element={<Settings />} />
    </Routes>
  );
}

export default AppRoutes;
